def assemble_context(query: str, docs: List[str]) -> str:
    context = []
    for i, doc in enumerate(docs):
        context.append(f'[DOC-{i}] {doc}')
    context_str = '\n\n'.join(context)

    prompt = f"""
Answer the query using ONLY the provided context. Cite sources with [DOC-X].

Query: {query}

Context: {context_str}

Answer with citations:"""
    return prompt

