from vex_sdk import Vex, ResultValidator
from typing import Dict, Any

vex = Vex(api_key='your-vex-key')

@vex.result_validator(name='rag-faithfulness')
def check_source_faithfulness(result: RAGResponse, context: List[str], query: str) -> Dict[str, Any]:
    verdict = vex.evaluate.fidelity_check(
        claim=result.answer,
        grounding_docs=context,
        task='factual_synthesis'
    )

    if verdict.score < 0.85:
        return {
            'pass': False,
            'reason': f'Low faithfulness score: {verdict.score}',
            'citations': result.citations
        }
    return {'pass': True, 'score': verdict.score}

# Attach to agent
rag_agent.result_validators.append(check_source_faithfulness)

@vex.result_validator(name='citation-accuracy')
def validate_citations(result: RAGResponse, raw_context: List[str]) -> Dict[str, Any]:
    issues = []
    for citation in result.citations:
        doc_id = citation.chunk_id
        if doc_id >= len(raw_context):
            issues.append(f'Invalid doc_id: {doc_id}')
            continue

        snippet = raw_context[doc_id][citation.start_char:citation.end_char]
        if len(snippet.strip()) < 10:
            issues.append(f'Empty citation span: {citation}')

    return {
        'pass': len(issues) == 0,
        'issues': issues,
        'citation_count': len(result.citations)
    }

rag_agent.result_validators.append(validate_citations)

@vex.result_validator(name='rag-safety-net')
def rag_safety_net(result: RAGResponse, context: List[str], query: str) -> Dict[str, Any]:
    # Hallucination check
    hallucination_score = vex.evaluate.semantic_similarity(
        result.answer, ' '.join(context)
    )

    # Context relevance
    relevance_score = vex.evaluate.query_relevance(
        query=query,
        contexts=context,
        answer=result.answer
    )

    scores = {
        'hallucination': hallucination_score,
        'relevance': relevance_score,
        'confidence': result.confidence
    }

    return {
        'pass': hallucination_score > 0.75 and relevance_score > 0.8,
        'scores': scores
    }

rag_agent.result_validators.append(rag_safety_net)
